// Define a React functional component
const MyComponent = () => {
  const [arr, setArr] = useState([]);
  const sum = arr.reduce((a, b) => a + b, 0);
  return <div>{sum}</div>;
};

// Define the App component
const App = () => {
  const [n, setN] = useState(3);
  const [arr, setArr] = useState([1, 2, 3]);
  return <MyComponent n={n} arr={arr} />;
};

